package com.example.secondphone.controller;
import java.util.List;import org.springframework.security.access.prepost.PreAuthorize;import org.springframework.web.bind.annotation.*;import com.example.secondphone.dto.*;import com.example.secondphone.service.MemberService;import io.swagger.v3.oas.annotations.tags.Tag;import jakarta.validation.Valid;
@RestController @RequestMapping("/api/admin/members") @Tag(name="後台會員",description="後台會員查詢、停權與角色管理")
public class AdminMemberController{private final MemberService service;public AdminMemberController(MemberService service){this.service=service;}@GetMapping public List<MemberResponse> list(@RequestParam(required=false)String keyword){return service.search(keyword).stream().map(MemberResponse::from).toList();}@GetMapping("/{id}") public MemberResponse detail(@PathVariable Long id){return MemberResponse.from(service.findById(id));}@PatchMapping("/{id}/status") public MemberResponse status(@PathVariable Long id,@Valid @RequestBody MemberStatusUpdateRequest q){return MemberResponse.from(service.updateStatus(id,q.status()));}@PatchMapping("/{id}/role") @PreAuthorize("hasRole('ADMIN')") public MemberResponse role(@PathVariable Long id,@Valid @RequestBody MemberRoleUpdateRequest q){return MemberResponse.from(service.updateRole(id,q.role()));}}
